#!/bin/bash
echo "============================================"
echo "  FlipSlab Engine - Update v7b"
echo "============================================"
PROJECT_DIR=""
if [ -d "/opt/gradeprophet" ]; then PROJECT_DIR="/opt/gradeprophet"
elif [ -d "/home/gradeprophet" ]; then PROJECT_DIR="/home/gradeprophet"
else echo "ERROR"; exit 1; fi
echo "Dir: $PROJECT_DIR"
echo "=== Keys ==="
EXISTING_OPENAI=$(grep "^OPENAI_API_KEY=" "$PROJECT_DIR/backend/.env" 2>/dev/null | cut -d'=' -f2-)
LLAVES_FILE=""
if [ -f "/home/flipcardsuni2/public_html/llaves.txt" ]; then LLAVES_FILE="/home/flipcardsuni2/public_html/llaves.txt"
elif [ -f "$PROJECT_DIR/llaves.txt" ]; then LLAVES_FILE="$PROJECT_DIR/llaves.txt"; fi
if [ -n "$LLAVES_FILE" ]; then
    MONGO_URL=$(grep "^MONGO_URL=" "$LLAVES_FILE" | cut -d'=' -f2-)
    DB_NAME=$(grep "^DB_NAME=" "$LLAVES_FILE" | cut -d'=' -f2-)
    OPENAI_API_KEY=$(grep "^OPENAI_API_KEY=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_CLIENT_ID=$(grep "^EBAY_CLIENT_ID=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_CLIENT_SECRET=$(grep "^EBAY_CLIENT_SECRET=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_DEV_ID=$(grep "^EBAY_DEV_ID=" "$LLAVES_FILE" | cut -d'=' -f2-)
    EBAY_RUNAME=$(grep "^EBAY_RUNAME=" "$LLAVES_FILE" | cut -d'=' -f2-)
    REACT_APP_BACKEND_URL=$(grep "^REACT_APP_BACKEND_URL=" "$LLAVES_FILE" | cut -d'=' -f2-)
    [ -z "$OPENAI_API_KEY" ] && [ -n "$EXISTING_OPENAI" ] && OPENAI_API_KEY="$EXISTING_OPENAI"
    cat > "$PROJECT_DIR/backend/.env" << ENVFILE
MONGO_URL=${MONGO_URL:-mongodb://localhost:27017}
DB_NAME=${DB_NAME:-gradeprophet}
OPENAI_API_KEY=${OPENAI_API_KEY}
EBAY_CLIENT_ID=${EBAY_CLIENT_ID}
EBAY_CLIENT_SECRET=${EBAY_CLIENT_SECRET}
EBAY_DEV_ID=${EBAY_DEV_ID}
EBAY_RUNAME=${EBAY_RUNAME}
CORS_ORIGINS=*
ENVFILE
    [ -n "$REACT_APP_BACKEND_URL" ] && echo "REACT_APP_BACKEND_URL=${REACT_APP_BACKEND_URL}" > "$PROJECT_DIR/frontend/.env"
    echo "  .env OK"
fi
echo "=== Updating files ==="
cp "$PROJECT_DIR/backend/server.py" "$PROJECT_DIR/backend/server.py.bak" 2>/dev/null
base64 -d << 'S1' > "$PROJECT_DIR/backend/server.py"

S1
base64 -d << 'S2' > "$PROJECT_DIR/frontend/src/components/LandingPage.jsx"

S2
base64 -d << 'S3' > "$PROJECT_DIR/frontend/src/App.js"

S3
base64 -d << 'S4' > "$PROJECT_DIR/frontend/src/components/FlipFinder.jsx"

S4
base64 -d << 'S5' > "$PROJECT_DIR/frontend/src/components/CardScanner.jsx"

S5
base64 -d << 'S6' > "$PROJECT_DIR/frontend/src/components/AnalysisResult.jsx"

S6
base64 -d << 'S7' > "$PROJECT_DIR/frontend/src/components/EbayMonitor.jsx"

S7
base64 -d << 'S8' > "$PROJECT_DIR/frontend/src/components/HistoryPanel.jsx"

S8
base64 -d << 'S9' > "$PROJECT_DIR/frontend/src/components/LearningPanel.jsx"

S9
base64 -d << 'S10' > "$PROJECT_DIR/frontend/src/pages/Dashboard.jsx"

S10
echo "  All files OK"
echo "=== Build frontend ==="
cd "$PROJECT_DIR/frontend" && npm run build 2>&1 | tail -5
echo "=== Restart backend ==="
if [ -f "$PROJECT_DIR/restartback.sh" ]; then bash "$PROJECT_DIR/restartback.sh"
else pkill -f "uvicorn.*server:app" 2>/dev/null; cd "$PROJECT_DIR/backend"; nohup python3 -m uvicorn server:app --host 0.0.0.0 --port 8001 > "$PROJECT_DIR/backend/backend.log" 2>&1 & fi
echo "  Done"
echo "============================================"
echo "  UPDATE v7b COMPLETE - All English!"
echo "============================================"
